<style>
	.sof-orbiter-container {
		margin-bottom: 3rem;
		--lime: #52B788;
		display: flex;
		justify-content: center;
		align-items: center;
		position: relative;
	}
	.sof-orbiter-ring {
		width: 20rem;
		height: 20rem;
		border-radius: 50%;
		border: 2px solid rgba(82,183,136,0.2);
		display: flex;
		align-items: center;
